import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import React, {useState} from 'react';
import Header from './components/Header';
import Card from './components/Card';
import {product} from './data/products';
import './styles/main.css';


function App() {
    const [cart, setCart] = useState([]);
    const [isCartOpen, setIsCartOpen] = useState

    return (
        <Router> {/* Обертка для работы ссылок */}
        <div className="App">
            <Header cartCount={cart.length} />

            <Routes>
            {/* Главная страница */}
            <Route path="/" element={
                <div style={{ textAlign: 'center', padding: '100px' }}>
                <h1>Добро пожаловать в ONeBoutique</h1>
                <p>Премиальная одежда для ценителей стиля</p>
                <a href="/catalog" style={{ color: '#800020', fontWeight: 'bold' }}>Перейти в каталог →</a>
                </div>
            } />

            {/* Страница каталога */}
            <Route path="/catalog" element={
                <main style={{ padding: '40px', display: 'flex', gap: '20px', flexWrap: 'wrap', justifyContent: 'center' }}>
                {product.map(item => (
                    <Card key={item.id} product={item} onAdd={(p) => setCart([...cart, p])} />
                ))}
                </main>
            } />
            </Routes>
        </div>
        </Router>
    );
}

export default App;
